import numpy as np

def prefix_tune_attention_keys(keys, prefix_keys):
    return np.concatenate([prefix_keys, keys], axis=0)

def run_practice():
    k = np.array([[1.0]])
    pk = np.array([[2.0]])
    merged = prefix_tune_attention_keys(k, pk)
    assert np.allclose(merged, np.array([[2.0], [1.0]]))
    print('[PASS] Prefix tuning key injection validated.')

if __name__ == '__main__':
    run_practice()
